171→  points?: number;
172→  isLoading?: boolean;
173→  hasError?: boolean;
174→}) {
175→  const [isMyOrders, setIsMyOrders] = useState(false);
176→
177→  useEffect(() => {
178→    seedStore(points);
179→  }, [points]);
180→
181→  return (
