413→      hasTrackedSearchPress.current = true;
414→    }
415→  }, []);
416→
417→  const getFilterGroups: FilterGroup[] = useMemo(() => {
418→    return [
419→      {
420→        label: 'Períodos',
421→        options: [
422→          {
423→            label: '7 dias',
424→            value: 0,
425→          },
426→          {
427→            label: '15 dias',
428→            value: 1,
429→          },
430→          {
431→            label: '30 dias',
432→            value: 2,
433→          },
434→          {
435→            label: '60 dias',
436→            value: 3,
437→          },
438→          {
439→            label: '90 dias',
440→            value: 4,
441→          },
442→        ],
443→      },
444→      {
445→        label: 'Tipos de lançamentos',
446→        options: [
447→          {
448→            label: 'Ganhos',
449→            value: 'CREDIT',
450→          },
451→          {
452→            label: 'Usados',
453→            value: 'RESCUE',
454→          },
455→          {
456→            label: 'Expirados',
457→            value: 'EXPIRED',
458→          },
459→        ],
460→      },
461→    ];
462→  }, []);
463→
464→  const getInitialFilters = useMemo(() => {
465→    const filters: Record<number, unknown> = {};
466→    if (
467→      appliedTransactionsFilters?.period !== undefined &&
468→      appliedTransactionsFilters?.period !== null
