135→export async function getPointsBalance(): Promise<void> {
136→  const { pointsExtractActions, pointsBalance } = useRootStore.getState();
137→
138→  if (!shouldFetchBalance(pointsBalance.status)) {
139→    return;
140→  }
141→
142→  try {
143→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.LOADING);
144→
145→    const response = await getPointsBalanceApi();
146→    const returnCode =
147→      response?.data?.status?.returnCode ??
148→      response?.data?.status?.codigoRetorno;
149→    const points = response?.data?.data?.points;
150→
151→    if (returnCode === EXTRACT_CONSTANTS.BALANCE_SUCCESS_RETURN_CODE) {
152→      handleBalanceSuccess(points);
153→      return;
154→    }
155→
156→    handleBalanceError();
157→  } catch {
158→    handleBalanceError();
159→  }
