148→    const period = filtersToApply[0];
149→    const type = filtersToApply[1];
150→
151→    const contentIdParts = ['filtrar'];
152→    if (period) contentIdParts.push(String(period));
153→    if (type) {
154→      const typeLabel = TYPE_LABELS[type as TransactionType] || type;
155→      contentIdParts.push(typeLabel.toLowerCase());
156→    }
157→
158→    const contentId = contentIdParts.join('_').toLowerCase();
159→
160→    eventSelectContent({
161→      content_type: 'cta',
162→      content_id: contentId,
163→      location_1: 'monetizacao',
164→      location_2: 'hub_recompensas_spmais',
165→      location_3: 'filtro_extrato_hub',
166→    });
167→
168→    modalizeRef.current?.close?.();
169→
170→    setTimeout(() => {
171→      onApplyFilters(filtersToApply);
172→    }, 100);
173→  }, [
174→    selectedFilters,
175→    onApplyFilters,
176→    modalizeRef,
177→  ]);
178→
179→  return (
180→    <BackDropBottom modalizeRef={modalizeRef} pd="none">
181→      <Box mt="xxs">
182→        <Box>
183→          {filterGroups.map((group, groupIndex) => (
184→            <MemoizedFilterGroup
185→              key={groupIndex}
186→              group={group}
187→              groupIndex={groupIndex}
188→              selectedIndex={selectedIndices[groupIndex]}
189→              filterItems={filterItemsMap[groupIndex]}
190→              onFilterChange={handleFilterChange}
191→            />
192→          ))}
193→        </Box>
194→
195→        <Box mt="small" direction width={screenWidth} ml="small">
196→          <Button
197→            text="Limpar"
198→            width={screenWidth * 0.43}
199→            type="secundaryMedium"
200→            onPress={handleClear}
