202→          <Button
203→            width={screenWidth * 0.43}
204→            text="Filtrar"
205→            type="primaryMedium"
206→            ml="xs"
207→            onPress={handleApply}
208→          />
209→        </Box>
210→      </Box>
211→    </BackDropBottom>
212→  );
213→};
